      return (reader.readDateTimeOrNull(offset)) as P;
    case 1:
      return (reader.readBool(offset)) as P;
    case 2:
      return (reader.readLong(offset)) as P;
    case 3:
      return (reader.readString(offset)) as P;
    case 4:
      return (reader.readString(offset)) as P;
    case 5:
      return (reader.readString(offset)) as P;
    default:
      throw IsarError('Unknown property with id $propertyId');
  }
}

Id _milestoneGetId(Milestone object) {
  return object.id;
}

List<IsarLinkBase<dynamic>> _milestoneGetLinks(Milestone object) {
  return [object.goal, object.tasks];
}

void _milestoneAttach(IsarCollection<dynamic> col, Id id, Milestone object) {
  object.id = id;
  object.goal.attach(col, col.isar.collection<Goal>(), r'goal', id);
  object.tasks.attach(col, col.isar.collection<Task>(), r'tasks', id);
}

